do Tabs.Changelog:AddParagraph({Title="📝 PATCH NOTES (Update: 27 Maret 2026 | 22:14 WIB)",Content="(+) Rework besar-besaran Pergantian UI menggunakan Library v2.4 Uegenewu\n"   .. "(+) Menambahkan sistem Tema UI (Theme Selector) di Tab Config (Tersimpan otomatis).\n"   .. "(+) Menambahkan sistem Level untuk kandang sapi\n"   .. "(+) Menambahkan item Event Collab Shope (Baju, Helm, Tas) pada ETC Fitur.\n"   .. "(+) Menambahkan sistem Profit Tracker (Cek Keuntungan) pada menu Jual Panen Instan.\n"   .. "(+) Menambahkan Fitur Troll Drop Payung & Layang-layang\n"   .. "(+) Menambahkan storage pada menu shop\n"   .. "(/) Improve Webhook, sekarang tampilan webhook jauh lebih rapih dan keren\n"   .. "(/) Tombol Logo UI disempurnakan\n"   .. "(/) Auto Sell Durian & Sawit\n"   .. "(/) Rework Menu Jual Panen: Kini membypass data server (langsung jual tanpa perlu item fisik di tas).\n"   .. "(/) UI Jual Panen diperbarui: Toggle Jual Semua diganti menjadi 2 tombol terpisah agar lebih praktis.\n"   .. "(/) Sinkronisasi Smart Lock: Tombol Mandi, Storage, Troll Drop, Aksesoris, dan Teleport kini otomatis terkunci saat Auto Farming berjalan untuk mencegah Glitch/Bug.\n"   .. "(/) Bypass Smart Lock: Fitur Beli & Jual Instan kini bisa digunakan bersamaan sambil Auto Farming (Kaitun/SA).\n"   .. "(-) Fitur Keybind PC & Hotkey PC (Dihapus)" });Tabs.Changelog:AddParagraph({Title="👨‍💻 DEVELOPER INFO",Content="Developer: migii corleone\nStatus: Undetected & Optimized\n\nThanks for euegenewu (Lunar Dev Script) For Library UI nya"});local ParaDashMon=Tabs.Monitor:AddParagraph({Title="📈 GLOBAL LIVE DASHBOARD",Content="Loading data..."});local ParaTanUI=Tabs.Monitor:AddParagraph({Title="🌾 PANEL TANAMAN",Content="Loading data..."});local ParaHewUI=Tabs.Monitor:AddParagraph({Title="🐮 PANEL HEWAN TERNAK",Content="Loading data..."});local ParaInvUI=Tabs.Monitor:AddParagraph({Title="🎒 INVENTORY (TAS)",Content="Loading data..."});local SecMonitorTog=Tabs.Monitor:AddSection({Title="⚙️ PENGATURAN PANEL MELAYANG"});SecMonitorTog:AddNote({Text="Nyalakan fitur di bawah ini untuk memunculkan panel secara melayang (Floating) di layar HP-mu."});local TogGlobalDash=SecMonitorTog:AddToggle({Text="Tampilkan Global Live Dashboard",Default=false,Callback=function(v) PanelDashboardGlobal.Visible=v;end});SecMonitorTog:AddToggle({Text="Tampilkan Info Tanaman",Default=false,Callback=function(v) PanelTanaman.Visible=v;end});SecMonitorTog:AddToggle({Text="Tampilkan Info Hewan Ternak",Default=false,Callback=function(v) PanelHewan.Visible=v;end});SecMonitorTog:AddToggle({Text="Tampilkan Inventory / Backpack",Default=false,Callback=function(v) PanelInventory.Visible=v;end});local ParaDashboard=Tabs.Kaitun:AddParagraph({Title="📊 LIVE DASHBOARD",Content="Loading data..."});local TutText="📖 CARA PENGGUNAAN:\n"   .. "1. Berdiri di area kosong Lahan Biasa, lalu klik '1. Set Lahan Biasa'. (Posisi ini akan disimpan secara permanen, dan karakter akan otomatis kembali kesini setelah mengurus kandang/lahan besar).\n"   .. "2. Klik '2. Scan Bibit Di Tas'.\n"   .. "3. Pilih Bibit 1 dan Bibit 2 (Gunakan Single Seed jika hanya 1 bibit).\n"   .. "4. Atur Limit Tanam (Ketik angka, misal 15. Kosongkan untuk Unlimited).\n"   .. "5. Pilih Mode Kaitun,\n"   .. "6. Pilih Level Kandang sapi, (Sesuai Level Kandang kamu) Setelah itu langsung Auto Kaitun start." ;local TutText2="🌟 PENJELASAN MODE:\n"   .. "• Mode 1 (All In): Mengurus Semuanya (Lahan Besar, Lahan Biasa, Ayam & Sapi).\n"   .. "• Mode 2: Fokus Lahan Besar & Lahan Biasa saja.\n"   .. "• Mode 3: Fokus Lahan Besar, Lahan Biasa & Ayam (Tanpa Sapi).\n"   .. "• Mode 4: Fokus farming Lahan Biasa saja (Multi-seed)\n\n"   .. "🌟 PENJELASAN LEVEL KANDANG:\n"   .. "• Level 1 (3 Sapi)\n"   .. "• Level 2 (6 Sapi)\n"   .. "• Level 3 (9 Sapi)\n"   .. "• Level 4 (12 Sapi)\n"   .. "• Level 5 (15 Sapi)" ,Tabs.Kaitun:AddParagraph({Title="📖      PANDUAN & TUTORIAL",Content=TutText});Tabs.Kaitun:AddParagraph({Title="📖      PENJELASAN MODE",Content=TutText2});Tabs.Kaitun:AddTextBox({Text="Batas Limit Tanam (Kaitun)",Placeholder="Contoh: 15 (Kosongkan utk Unlimited)",Callback=function(text) local num=tonumber(text);if num then if (num>25) then num=25;end if (num<1) then num=1;end customLimit=math.floor(num);else customLimit="Unlimited";end sendNotification("Batas Limit Kaitun diatur ke: "   .. tostring(customLimit) );end});Tabs.Kaitun:AddButton({Text="📍 1. Set Lahan Biasa (Berdiri disini)",Callback=function() local hrp=player.Character and player.Character:FindFirstChild("HumanoidRootPart") ;if hrp then local flatLook=Vector3.new(hrp.CFrame.LookVector.X,0,hrp.CFrame.LookVector.Z);if (flatLook.Magnitude>0) then flatLook=flatLook.Unit;else flatLook=Vector3.new(0,0, -1);end local lookAtPos=hrp.Position + flatLook ;savedPlantLocationCFrame=CFrame.lookAt(hrp.Position,lookAtPos);kaitunPlantModeData={x=0,z=0,dx=0,dz= -1,lineStep=1,circleStep=1,circleRadius=0.2,maxCircleSteps=6};if writefile then pcall(function() writefile(kaitunPosConfigFile,HttpService:JSONEncode({x=hrp.Position.X,y=hrp.Position.Y,z=hrp.Position.Z,lx=lookAtPos.X,ly=lookAtPos.Y,lz=lookAtPos.Z}));end);end sendNotification("✅ Posisi Lahan Tersimpan secara Permanen!");end end});Tabs.Kaitun:AddButton({Text="🔍 2. Scan Bibit Di Tas",Callback=function() pcall(function() sendNotification("⏳ Sedang memindai tas Anda...");local foundBibit={};local char=player.Character;local backpack=player:FindFirstChild("Backpack");local function cleanBibitName(name) local base=string.gsub(name,"%s*[%[%(]?%d+[%]%)]?$","");base=string.gsub(base,"%s*[xX]%d+$","");return string.match(base,"^%s*(.-)%s*$") or name ;end local function cekItem(item) if item:IsA("Tool") then local namaLower=string.lower(item.Name);if (string.find(namaLower,"bibit") and  not string.find(namaLower,"sawit") and  not string.find(namaLower,"durian")) then foundBibit[cleanBibitName(item.Name)]=true;end end end if char then for _,item in ipairs(char:GetChildren()) do cekItem(item);end end if backpack then for _,item in ipairs(backpack:GetChildren()) do cekItem(item);end end local options1={};local options2={"❌ Single Seeds"};for k,_ in pairs(foundBibit) do table.insert(options1,k);table.insert(options2,k);end if ( #options1==0) then table.insert(options1,"Tidak ada bibit di tas");end if _G.DropKaitun1 then _G.DropKaitun1:Refresh(options1);_G.DropKaitun1:SetValue(options1[1]);end if _G.DropKaitun2 then _G.DropKaitun2:Refresh(options2);_G.DropKaitun2:SetValue(options2[1]);end sendNotification("✅ Scan selesai! Silakan pilih bibit di bawah.");end);end});_G.DropKaitun1=Tabs.Kaitun:AddDropdown({Text="🔽 Pilih Bibit 1...",Items={"Scan Bibit Dulu!"},Multi=false,Default="Scan Bibit Dulu!",Callback=function(v) selectedBibit1Name=v;sendNotification("Bibit 1 dipilih: "   .. v );end});_G.DropKaitun2=Tabs.Kaitun:AddDropdown({Text="🔽 Pilih Bibit 2 (Opsional)...",Items={"Scan Bibit Dulu!"},Multi=false,Default="Scan Bibit Dulu!",Callback=function(v) if (v=="❌ Single Seeds") then selectedBibit2Name=nil;sendNotification("Mode Single Seed diaktifkan.");else selectedBibit2Name=v;sendNotification("Bibit 2 dipilih: "   .. v );end end});Tabs.Kaitun:AddDropdown({Text="🔄 Mode Kaitun",Items=kaitunModesText,Multi=false,Default=kaitunModesText[1],Callback=function(v) for i,text in ipairs(kaitunModesText) do if (text==v) then currentKaitunMode=i;break;end end end});local limitSapi=15;local listLevelSapi={"Level 1 (3 Sapi)","Level 2 (6 Sapi)","Level 3 (9 Sapi)","Level 4 (12 Sapi)","Level 5 (15 Sapi)"};Tabs.Kaitun:AddDropdown({Text="🐄 Level Kandang Sapi",Items=listLevelSapi,Multi=false,Default=listLevelSapi[5],Callback=function(v) if (v=="Level 1 (3 Sapi)") then limitSapi=3;elseif (v=="Level 2 (6 Sapi)") then limitSapi=6;elseif (v=="Level 3 (9 Sapi)") then limitSapi=9;elseif (v=="Level 4 (12 Sapi)") then limitSapi=12;elseif (v=="Level 5 (15 Sapi)") then limitSapi=15;end sendNotification("✅ Target sapi diubah menjadi "   .. tostring(limitSapi)   .. " ekor!" );end});local TogKaitunPrivate=Tabs.Kaitun:AddToggle({Text=